// Validate webhook payload. Sets valid=false to flip Node 03 to error branch.
const body = $input.first().json.body || $input.first().json;
const errors = [];

const required = ['subcontractor_id', 'document_type', 'issued_for_occurrence', 'issued_by'];
for (const f of required) {
  if (!body[f] || String(body[f]).trim() === '') errors.push(`missing:${f}`);
}

const allowedTypes = ['cert', 'w9', 'lien_waiver', 'other'];
if (body.document_type && !allowedTypes.includes(body.document_type)) {
  errors.push(`bad_document_type:${body.document_type}`);
}

// Must match CHECK constraint on document_collection_tokens.issued_by
const allowedIssuedBy = ['w9_workflow', 'lien_workflow', 'cert_workflow', 'manual', 'api'];
if (body.issued_by && !allowedIssuedBy.includes(body.issued_by)) {
  errors.push(`bad_issued_by:${body.issued_by}`);
}

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (body.subcontractor_id && !uuidRe.test(body.subcontractor_id)) {
  errors.push('bad_uuid:subcontractor_id');
}
if (body.site_order_id && !uuidRe.test(body.site_order_id)) {
  errors.push('bad_uuid:site_order_id');
}

const allowedOccurrenceNames = ['Initial Request','First Reminder','Second Reminder','Final Notice','Manual Escalation','Off-Cycle Reminder'];
const occurrenceName = body.occurrence_name || 'Off-Cycle Reminder';
if (!allowedOccurrenceNames.includes(occurrenceName)) errors.push(`bad_occurrence_name:${occurrenceName}`);

const ttlHours = Number(body.ttl_hours || 48);
if (!Number.isFinite(ttlHours) || ttlHours < 1 || ttlHours > 240) {
  errors.push('bad_ttl_hours');
}

return [{
  json: {
    valid: errors.length === 0,
    errors,
    body: {
      subcontractor_id:       body.subcontractor_id,
      document_type:          body.document_type,
      site_order_id:          body.site_order_id || null,
      issued_for_occurrence:  body.issued_for_occurrence,
      issued_by:              body.issued_by,
      ttl_hours:              ttlHours,
      verification_required:  body.verification_required !== false,
      occurrence_name:        occurrenceName
    }
  }
}];
